"""
Quality Recovery Engine for OpenCode
Restores instant responses for simple inputs while preserving advanced features for complex workflows
Implements three-tier response system: Instant -> Standard -> Observer
"""

import re
import time
import asyncio
from typing import Dict, List, Optional, Tuple, Any, Union
from dataclasses import dataclass, asdict
from enum import Enum
import json

class ResponseTier(Enum):
    """Response processing tiers"""
    INSTANT = "instant"      # 0.1-0.5s - Simple inputs, direct model call
    STANDARD = "standard"    # 1-3s - Medium complexity, current system
    OBSERVER = "observer"    # 5-30s - Complex workflows, observer pattern

class InputComplexity(Enum):
    """Input complexity classification"""
    TRIVIAL = "trivial"      # Single words, greetings, basic math
    SIMPLE = "simple"        # Short queries, basic commands
    MEDIUM = "medium"        # Standard complexity requiring some analysis
    COMPLEX = "complex"      # Multi-step workflows, research queries

@dataclass
class QualityMetrics:
    """Quality and performance metrics"""
    response_time: float
    tier_used: ResponseTier
    complexity_detected: InputComplexity
    bypass_activated: bool
    rag_activated: bool
    observer_activated: bool
    quality_score: float = 0.0

@dataclass
class FastPathConfig:
    """Configuration for fast path optimization"""
    enable_fast_path: bool = True
    instant_response_threshold: float = 0.5  # seconds
    complexity_analysis_threshold: int = 10   # word count
    rag_activation_threshold: float = 0.6    # complexity score
    observer_activation_threshold: float = 0.7  # complexity score

class FastPathDetector:
    """Detects when inputs can use instant response path"""

    def __init__(self):
        # Patterns for instant responses
        self.trivial_patterns = [
            r'^\w{1,3}$',                    # 1-3 characters: "hi", "no", "ls"
            r'^\d+\s*[\+\-\*/]\s*\d+$',      # Simple math: "2+2", "10 * 5"
            r'^(hello|hi|hey|thanks?|thank you|yes|no|ok|okay)$',  # Greetings
            r'^/\w+(\s+\w+)?$',              # Commands: "/help", "/mode auto"
            r'^\w+\?$',                      # Single word questions: "ready?"
        ]

        # Patterns for simple responses (bypass heavy analysis)
        self.simple_patterns = [
            r'^(what|how|when|where|why|who)\s+is\s+\w+',  # Basic questions
            r'^(show|list|display)\s+\w+',                 # Simple requests
            r'^(run|execute)\s+\w+',                       # Basic commands
            r'^\w+\s+(help|info|status|version)$',         # Info requests
        ]

        # Keywords that indicate research/RAG needed
        self.research_keywords = [
            'research', 'investigate', 'analyze deeply', 'comprehensive',
            'compare multiple', 'latest information', 'current trends',
            'best practices', 'industry standards', 'recent developments'
        ]

        # Keywords that indicate observer pattern needed
        self.observer_keywords = [
            'workflow', 'multi-step', 'analyze and then', 'first.*then',
            'process.*review.*refine', 'multiple models', 'verify.*combine'
        ]

    def classify_input_complexity(self, user_input: str) -> InputComplexity:
        """Classify input complexity for appropriate processing tier"""

        text = user_input.strip()
        word_count = len(text.split())

        # Trivial inputs - instant response
        if word_count <= 3:
            for pattern in self.trivial_patterns:
                if re.match(pattern, text, re.IGNORECASE):
                    return InputComplexity.TRIVIAL

        # Simple inputs - bypass heavy analysis
        if word_count <= 10:
            for pattern in self.simple_patterns:
                if re.match(pattern, text, re.IGNORECASE):
                    return InputComplexity.SIMPLE

        # Check for complex indicators
        text_lower = text.lower()

        # Observer pattern indicators
        if any(keyword in text_lower for keyword in self.observer_keywords):
            return InputComplexity.COMPLEX

        # Research indicators
        if any(keyword in text_lower for keyword in self.research_keywords):
            return InputComplexity.COMPLEX

        # Long inputs are typically complex
        if word_count > 50:
            return InputComplexity.COMPLEX

        # Medium complexity by default
        return InputComplexity.MEDIUM

    def should_bypass_complexity_analysis(self, user_input: str) -> bool:
        """Determine if input should bypass full complexity analysis"""
        complexity = self.classify_input_complexity(user_input)
        return complexity in [InputComplexity.TRIVIAL, InputComplexity.SIMPLE]

    def should_activate_rag(self, user_input: str, complexity: InputComplexity) -> bool:
        """Determine if RAG should be activated for this input"""
        if complexity == InputComplexity.TRIVIAL:
            return False

        if complexity == InputComplexity.SIMPLE:
            # Only activate RAG for simple inputs with research keywords
            text_lower = user_input.lower()
            return any(keyword in text_lower for keyword in self.research_keywords[:3])

        # Activate RAG for medium and complex inputs
        return complexity in [InputComplexity.MEDIUM, InputComplexity.COMPLEX]

    def should_use_observer_pattern(self, user_input: str, complexity: InputComplexity,
                                  complexity_score: Optional[float] = None) -> bool:
        """Determine if observer pattern should be used"""
        if complexity in [InputComplexity.TRIVIAL, InputComplexity.SIMPLE]:
            return False

        if complexity == InputComplexity.COMPLEX:
            return True

        # For medium complexity, check score if available
        if complexity_score is not None and complexity_score > 0.7:
            return True

        # Check for explicit workflow keywords
        text_lower = user_input.lower()
        return any(keyword in text_lower for keyword in self.observer_keywords)

class QualityRecoveryEngine:
    """Main engine for quality recovery and tiered response system"""

    def __init__(self, config: FastPathConfig = None):
        self.config = config or FastPathConfig()
        self.detector = FastPathDetector()
        self.performance_metrics = []

        # Cache for frequent simple queries
        self.response_cache = {}
        self.cache_max_size = 100

    async def process_input_with_quality_recovery(self, user_input: str,
                                                interactive_instance,
                                                **kwargs) -> Tuple[str, QualityMetrics]:
        """Process input using quality recovery three-tier system"""

        start_time = time.time()

        # Classify input complexity
        complexity = self.detector.classify_input_complexity(user_input)

        # Determine processing tier
        tier = self._determine_processing_tier(complexity, user_input)

        # Initialize metrics
        metrics = QualityMetrics(
            response_time=0.0,
            tier_used=tier,
            complexity_detected=complexity,
            bypass_activated=False,
            rag_activated=False,
            observer_activated=False
        )

        try:
            # Route to appropriate processing tier
            if tier == ResponseTier.INSTANT:
                response = await self._process_instant_tier(
                    user_input, interactive_instance, metrics
                )
            elif tier == ResponseTier.STANDARD:
                response = await self._process_standard_tier(
                    user_input, interactive_instance, metrics, complexity
                )
            else:  # ResponseTier.OBSERVER
                response = await self._process_observer_tier(
                    user_input, interactive_instance, metrics
                )

        except Exception as e:
            # Fallback to standard processing
            print(f"Quality recovery failed, using fallback: {e}")
            response = await self._fallback_processing(user_input, interactive_instance)
            metrics.tier_used = ResponseTier.STANDARD

        # Update metrics
        metrics.response_time = time.time() - start_time
        metrics.quality_score = self._calculate_quality_score(metrics)

        # Store metrics for analysis
        self.performance_metrics.append(metrics)
        if len(self.performance_metrics) > 1000:  # Keep last 1000 entries
            self.performance_metrics = self.performance_metrics[-500:]

        return response, metrics

    def _determine_processing_tier(self, complexity: InputComplexity, user_input: str) -> ResponseTier:
        """Determine which processing tier to use"""

        # TEMPORARY: Force standard tier for testing model generation
        return ResponseTier.STANDARD

    async def _process_instant_tier(self, user_input: str, interactive_instance,
                                  metrics: QualityMetrics) -> str:
        """Tier 1: Instant processing using hook-based recognition"""

        metrics.bypass_activated = True

        # Use instant hook engine for pattern recognition
        if not hasattr(self, 'hook_engine'):
            from .instant_hook_engine import InstantHookEngine
            self.hook_engine = InstantHookEngine()

        # Try instant hook recognition first
        hook_match = self.hook_engine.recognize_instant_pattern(user_input)
        if hook_match:
            # Instant response from hook system
            return hook_match.instant_response

        # Check legacy cache for fallback
        cache_key = user_input.lower().strip()
        if cache_key in self.response_cache:
            return self.response_cache[cache_key]

        # Handle remaining common patterns
        response = self._handle_common_patterns(user_input)
        if response:
            # Cache successful responses
            if len(self.response_cache) < self.cache_max_size:
                self.response_cache[cache_key] = response
            return response

        # Direct model call with minimal processing as final fallback
        try:
            # Use lightest possible model configuration
            original_resources = interactive_instance.config.runtime.resources
            interactive_instance.config.runtime.resources = 25  # Fast mode

            # Use the original generator to respect policy overrides
            response = await interactive_instance._original_generate_with_resources(
                user_input, "You are a helpful assistant. Give concise, direct answers.", 'standard'
            )

            # Restore original resources
            interactive_instance.config.runtime.resources = original_resources

            # Add to hook learning system for future recognition
            if hasattr(self, 'hook_engine'):
                self.hook_engine._record_unmatched_input(user_input)

            return response

        except Exception as e:
            print(f"Instant tier failed: {e}")
            # Fallback to standard processing
            return await self._fallback_processing(user_input, interactive_instance)

    def _handle_common_patterns(self, user_input: str) -> Optional[str]:
        """Handle very common patterns with pre-computed responses"""

        text = user_input.strip().lower()

        # Common greetings
        if text in ['hi', 'hello', 'hey']:
            return "Hello! How can I help you today?"

        if text in ['thanks', 'thank you']:
            return "You're welcome!"

        if text in ['yes', 'y']:
            return "Understood."

        if text in ['no', 'n']:
            return "Okay."

        # Simple math (basic patterns)
        math_match = re.match(r'^(\d+)\s*([+\-*/])\s*(\d+)$', text)
        if math_match:
            try:
                a, op, b = math_match.groups()
                a, b = int(a), int(b)
                if op == '+':
                    return str(a + b)
                elif op == '-':
                    return str(a - b)
                elif op == '*':
                    return str(a * b)
                elif op == '/' and b != 0:
                    return str(a // b) if a % b == 0 else f"{a/b:.2f}"
            except:
                pass

        # Basic commands
        if text.startswith('/'):
            command_responses = {
                '/help': "Available commands: /help, /mode, /model, /config",
                '/status': "System operational",
                '/version': "OpenCode v1.0 with Quality Recovery"
            }
            return command_responses.get(text)

        return None

    async def _process_standard_tier(self, user_input: str, interactive_instance,
                                   metrics: QualityMetrics, complexity: InputComplexity) -> str:
        """Tier 2: Standard processing with selective optimizations"""

        # Decide whether to use RAG
        use_rag = self.detector.should_activate_rag(user_input, complexity)
        metrics.rag_activated = use_rag

        if use_rag:
            # Use existing RAG system
            if hasattr(interactive_instance, 'pre_rag_optimizer'):
                try:
                    # Light RAG processing for standard tier
                    optimization_result = await interactive_instance.pre_rag_optimizer.optimize_query_enhancement(
                        user_input, ""
                    )
                    # Use optimization result if it shows improvement
                    if (optimization_result.optimized_content and
                        optimization_result.optimized_content != optimization_result.original_content):
                        user_input = optimization_result.optimized_content
                except Exception as e:
                    print(f"RAG optimization failed: {e}")

        # Use existing standard processing but with lighter complexity analysis
        if self.detector.should_bypass_complexity_analysis(user_input):
            metrics.bypass_activated = True
            metrics.tier_used = "bypass"
            # Skip complexity analysis overhead - use original method to avoid loops
            if hasattr(interactive_instance, '_original_generate_with_resources'):
                return await interactive_instance._original_generate_with_resources(
                    user_input, None, 'standard'
                )
            else:
                # As a last resort, route through original generator to honor streaming/budgets
                if hasattr(interactive_instance, '_original_generate_with_resources'):
                    return await interactive_instance._original_generate_with_resources(
                        user_input, None, 'standard'
                    )
                return await interactive_instance.ollama_client.generate(
                    user_input, None, 'standard'
                )
        else:
            # Use existing full processing
            return await self._fallback_processing(user_input, interactive_instance)

    async def _process_observer_tier(self, user_input: str, interactive_instance,
                                   metrics: QualityMetrics) -> str:
        """Tier 3: Observer pattern for complex workflows"""

        metrics.observer_activated = True

        # Import and use the adaptive workflow engine
        try:
            from .adaptive_workflow_engine import AdaptiveWorkflowEngine

            # Create workflow engine
            workflow_engine = AdaptiveWorkflowEngine(
                interactive_instance.quant_manager,
                interactive_instance.config
            )

            # Execute adaptive workflow
            result = await workflow_engine.execute_workflow(user_input, "auto")

            # Extract response from workflow result
            if 'final_result' in result and 'synthesized_response' in result['final_result']:
                return result['final_result']['synthesized_response']
            else:
                return f"Workflow completed with {result.get('agent_outputs', 0)} agent outputs"

        except Exception as e:
            print(f"Observer tier failed: {e}")
            # Fallback to standard processing (which uses original generator)
            return await self._fallback_processing(user_input, interactive_instance)

    async def _fallback_processing(self, user_input: str, interactive_instance) -> str:
        """Fallback to original processing method"""
        try:
            # Extract just the current user input from conversation history
            current_input = user_input
            if "\nUser: " in user_input:
                # Get the last user message
                parts = user_input.split("\nUser: ")
                current_input = parts[-1].strip()

            # Use the original method to avoid circular loops
            if hasattr(interactive_instance, '_original_generate_with_resources'):
                return await interactive_instance._original_generate_with_resources(current_input, None, 'standard')
            else:
                # Direct model call as last resort; prefer original generator if available
                if hasattr(interactive_instance, '_original_generate_with_resources'):
                    return await interactive_instance._original_generate_with_resources(
                        current_input, None, 'standard'
                    )
                return await interactive_instance.ollama_client.generate(
                    current_input, None, 'standard'
                )
        except Exception as e:
            return f"Error processing request: {e}"

    def _calculate_quality_score(self, metrics: QualityMetrics) -> float:
        """Calculate quality score based on metrics"""
        score = 1.0

        # Response time factor (faster is better)
        if metrics.response_time < 0.5:
            score += 0.2
        elif metrics.response_time < 2.0:
            score += 0.1
        elif metrics.response_time > 10.0:
            score -= 0.3

        # Tier appropriateness factor
        if metrics.tier_used == ResponseTier.INSTANT and metrics.complexity_detected in [InputComplexity.TRIVIAL, InputComplexity.SIMPLE]:
            score += 0.2
        elif metrics.tier_used == ResponseTier.OBSERVER and metrics.complexity_detected == InputComplexity.COMPLEX:
            score += 0.1

        # Bypass activation appropriateness
        if metrics.bypass_activated and metrics.complexity_detected in [InputComplexity.TRIVIAL, InputComplexity.SIMPLE]:
            score += 0.1

        return max(0.0, min(1.0, score))

    def get_performance_summary(self) -> Dict[str, Any]:
        """Get performance summary for analysis"""
        if not self.performance_metrics:
            return {}

        # Calculate averages by tier
        tier_metrics = {tier: [] for tier in ResponseTier}
        for metric in self.performance_metrics:
            tier_metrics[metric.tier_used].append(metric)

        summary = {}
        for tier, metrics in tier_metrics.items():
            if metrics:
                avg_time = sum(m.response_time for m in metrics) / len(metrics)
                avg_quality = sum(m.quality_score for m in metrics) / len(metrics)
                summary[tier.value] = {
                    'count': len(metrics),
                    'avg_response_time': round(avg_time, 3),
                    'avg_quality_score': round(avg_quality, 3),
                    'bypass_rate': sum(1 for m in metrics if m.bypass_activated) / len(metrics)
                }

        return summary

    def should_switch_to_higher_tier(self, recent_metrics: List[QualityMetrics]) -> bool:
        """Analyze if recent performance suggests switching to higher processing tier"""
        if len(recent_metrics) < 3:
            return False

        # If recent instant/standard tier responses have low quality, suggest upgrade
        low_quality_count = sum(1 for m in recent_metrics
                              if m.quality_score < 0.6 and
                              m.tier_used in [ResponseTier.INSTANT, ResponseTier.STANDARD])

        return low_quality_count > len(recent_metrics) * 0.5


# Testing function
async def test_quality_recovery():
    """Test the quality recovery system"""

    class MockInteractive:
        class MockConfig:
            class MockRuntime:
                resources = 50
            class MockModel:
                name = "test_model"
            runtime = MockRuntime()
            model = MockModel()

        class MockClient:
            async def generate(self, **kwargs):
                await asyncio.sleep(0.1)  # Simulate processing
                return f"Response to: {kwargs.get('prompt', 'unknown')}"

        def __init__(self):
            self.config = self.MockConfig()
            self.ollama_client = self.MockClient()

        async def _generate_with_resources(self, prompt, **kwargs):
            await asyncio.sleep(0.5)  # Simulate standard processing
            return f"Standard response to: {prompt}"

    print("🧪 Testing Quality Recovery Engine\n")

    # Initialize quality recovery
    quality_engine = QualityRecoveryEngine()
    mock_interactive = MockInteractive()

    # Test cases
    test_cases = [
        ("hi", "Should use instant tier"),
        ("2+2", "Should use instant tier with math"),
        ("What is Python?", "Should use standard tier"),
        ("Analyze this complex algorithm and then create a comprehensive optimization workflow using multiple models to verify results", "Should use observer tier"),
        ("/help", "Should use instant tier for command")
    ]

    print("📊 Test Results:")
    print("-" * 80)

    for input_text, description in test_cases:
        response, metrics = await quality_engine.process_input_with_quality_recovery(
            input_text, mock_interactive
        )

        print(f"Input: {input_text}")
        print(f"Description: {description}")
        print(f"Tier Used: {metrics.tier_used.value}")
        print(f"Complexity: {metrics.complexity_detected.value}")
        print(f"Response Time: {metrics.response_time:.3f}s")
        print(f"Bypass Activated: {metrics.bypass_activated}")
        print(f"Quality Score: {metrics.quality_score:.2f}")
        print(f"Response: {response[:50]}{'...' if len(response) > 50 else ''}")
        print("-" * 80)

    # Performance summary
    print("\n📈 Performance Summary:")
    summary = quality_engine.get_performance_summary()
    for tier, stats in summary.items():
        print(f"{tier.title()}: {stats['count']} requests, {stats['avg_response_time']}s avg, {stats['avg_quality_score']:.2f} quality")


if __name__ == "__main__":
    asyncio.run(test_quality_recovery())
